import{_ as s,o as n,c as e,ae as t}from"./chunks/framework.Dg21OTSi.js";const k=JSON.parse('{"title":"踩坑 MNN 转 BERT 模型","description":"","frontmatter":{},"headers":[],"relativePath":"blog/ml/mnn-bert-conversion-pitfalls.md","filePath":"blog/ml/mnn-bert-conversion-pitfalls.md","lastUpdated":1774667239000}'),i={name:"blog/ml/mnn-bert-conversion-pitfalls.md"};function o(l,a,p,r,h,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="踩坑-mnn-转-bert-模型" tabindex="-1">踩坑 MNN 转 BERT 模型 <a class="header-anchor" href="#踩坑-mnn-转-bert-模型" aria-label="Permalink to &quot;踩坑 MNN 转 BERT 模型&quot;">​</a></h1><blockquote><p>记录一次 ONNX 转 MNN 后的推理误差排查过程</p></blockquote><h2 id="问题现象" tabindex="-1">问题现象 <a class="header-anchor" href="#问题现象" aria-label="Permalink to &quot;问题现象&quot;">​</a></h2><p>使用以下命令测试 MNN 模型转换：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../tools/script/testMNNFromOnnx-ori.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Users/xin/Documents/code/MNN/demo/zhongshu/final_bert_mnn.onnx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DEBUG</span></span></code></pre></div><p><strong>转换成功，但推理报错：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Converted Success!</span></span>
<span class="line"><span>Check convert result by onnx, thredhold is 0.01</span></span>
<span class="line"><span>input_ids</span></span>
<span class="line"><span>attention_mask</span></span>
<span class="line"><span>output: logits</span></span>
<span class="line"><span>logits: (1, 8, )</span></span>
<span class="line"><span>TESTERROR logits value error : absMaxV:7.908714 - DiffMax 5.450233</span></span>
<span class="line"><span>Error for output logits</span></span>
<span class="line"><span>Save mnn result to .error director</span></span></code></pre></div><ul><li>✅ ONNX 推理正常</li><li>❌ MNN 模型推理误差巨大（<code>DiffMax</code> 高达 5.45+）</li></ul><h2 id="排查过程" tabindex="-1">排查过程 <a class="header-anchor" href="#排查过程" aria-label="Permalink to &quot;排查过程&quot;">​</a></h2><h3 id="第一步-数据类型检查" tabindex="-1">第一步：数据类型检查 <a class="header-anchor" href="#第一步-数据类型检查" aria-label="Permalink to &quot;第一步：数据类型检查&quot;">​</a></h3><p>尝试将模型改为 <code>int32</code> 后重新测试，但误差值（<code>DiffMax</code> 依然是 3.7+）和出错位置几乎没变。</p><p><strong>结论：</strong> 排除了最常见的&quot;数据类型越界&quot;问题。</p><h3 id="第二步-定位问题层" tabindex="-1">第二步：定位问题层 <a class="header-anchor" href="#第二步-定位问题层" aria-label="Permalink to &quot;第二步：定位问题层&quot;">​</a></h3><p>错误追溯到了 <code>/bert/embeddings/Constant</code> 附近。</p><p>仔细观察日志，Layer.3 的输出 Shape 是 <code>(1, 512, 312)</code>，说明序列长度是 512。</p><h2 id="核心原因" tabindex="-1">核心原因 <a class="header-anchor" href="#核心原因" aria-label="Permalink to &quot;核心原因&quot;">​</a></h2><p>对于 BERT 模型，Embedding 层由三部分组成：</p><ol><li><strong>Word Embeddings</strong> - 词嵌入</li><li><strong>Position Embeddings</strong> - 位置嵌入</li><li><strong>Token Type Embeddings (Segment)</strong> - 段嵌入</li></ol><p>问题出在 <strong>Position/Token Type Embeddings 的动态生成</strong>：</p><blockquote><p>在 PyTorch 导出 ONNX 时，如果没有锁死 Shape，ONNX 会用 <code>Shape → Gather → ConstantOfShape</code> 这一串极其复杂的胶水算子来动态生成全 0 的 Segment ID。</p><p><strong>MNN 经常无法正确处理 <code>ConstantOfShape</code> 或动态的 <code>Tile</code> 算子</strong>，导致相加时混入了未初始化的内存（也就是随机的极大垃圾值），从而让整个激活值彻底崩坏。</p></blockquote><h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2><h3 id="使用-onnxsim-锁死-shape-并化简模型" tabindex="-1">使用 onnxsim 锁死 Shape 并化简模型 <a class="header-anchor" href="#使用-onnxsim-锁死-shape-并化简模型" aria-label="Permalink to &quot;使用 onnxsim 锁死 Shape 并化简模型&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 确保安装了最新版的 onnxsim</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onnxsim</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 替换成你实际的 ONNX 文件名，强制指定 input_ids 和 attention_mask 的 Shape</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onnxsim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Users/xin/Documents/code/MNN/demo/zhongshu/bert_mnn_final_int32.onnx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        /Users/xin/Documents/code/MNN/demo/zhongshu/bert_mnn_sim.onnx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        --overwrite-input-shape</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input_ids:1,512</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attention_mask:1,512</span></span></code></pre></div><h3 id="重新测试" tabindex="-1">重新测试 <a class="header-anchor" href="#重新测试" aria-label="Permalink to &quot;重新测试&quot;">​</a></h3><p>化简成功后，用新生成的 <code>bert_mnn_sim.onnx</code> 去跑 <code>testMNNFromOnnx.py</code>，问题应该就解决了。</p><h2 id="经验总结" tabindex="-1">经验总结 <a class="header-anchor" href="#经验总结" aria-label="Permalink to &quot;经验总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题类型</th><th>症状</th><th>解决方案</th></tr></thead><tbody><tr><td>数据类型越界</td><td>DiffMax 异常大</td><td>检查并统一数据类型</td></tr><tr><td>动态 Shape 问题</td><td>DiffMax 异常大，定位到 Embedding 层</td><td>用 onnxsim 锁死 Shape</td></tr><tr><td>算子融合 Bug</td><td>特定层输出异常</td><td>简化模型或调整转换参数</td></tr></tbody></table><p><strong>关键要点：</strong> 在导出 ONNX 时尽量锁死输入 Shape，避免使用动态算子，可以大幅降低 MNN 转换后的兼容性问题。</p><hr><p><em>记录时间：2026-03-27</em></p>`,30)])])}const g=s(i,[["render",o]]);export{k as __pageData,g as default};
